# test_topological_sort.py
import pytest

from your_module import topological_sort


def is_valid_topo_order(order, graph):
    pos = {node: i for i, node in enumerate(order)}

    # All nodes that appear as keys in graph must be present in the output.
    expected_nodes = set(graph.keys())
    if not expected_nodes.issubset(pos.keys()):
        return False

    for u, neighbors in graph.items():
        for v in neighbors:
            # v may or may not be present as a key; if it isn't, we still expect it
            # to be in the output order due to DFS traversal.
            if v not in pos:
                return False
            if pos[u] > pos[v]:
                return False
    return True


def test_happy_path_simple_dag():
    graph = {
        "a": ["b", "c"],
        "b": ["d"],
        "c": ["d"],
        "d": []
    }
    order = topological_sort(graph)
    assert is_valid_topo_order(order, graph)


def test_happy_path_empty_graph():
    graph = {}
    assert topological_sort(graph) == []


def test_edge_case_self_loop():
    # This implementation does not detect cycles; a self-loop will violate
    # the topological property, so we assert that the output is not valid.
    graph = {"a": ["a"]}
    order = topological_sort(graph)
    assert not is_valid_topo_order(order, graph)


def test_edge_case_disconnected_components():
    graph = {
        "a": ["b"],
        "b": [],
        "c": ["d"],
        "d": []
    }
    order = topological_sort(graph)
    assert is_valid_topo_order(order, graph)


def test_edge_case_neighbor_not_in_keys_is_included():
    # 'b' appears only as a neighbor (not a key)
    graph = {"a": ["b"]}
    order = topological_sort(graph)
    assert is_valid_topo_order(order, graph)
    assert set(order) >= {"a", "b"}


def test_edge_case_multiple_edges_and_repeated_neighbors():
    graph = {
        "a": ["b", "b", "b"],
        "b": ["c", "c"],
        "c": []
    }
    order = topological_sort(graph)
    assert is_valid_topo_order(order, graph)


def test_error_case_graph_not_dict_raises_type_error():
    with pytest.raises(AttributeError):
        # The function uses graph.get(...) and iterates over graph;
        # passing a non-mapping should typically error.
        topological_sort(None)  # type: ignore[arg-type]


def test_error_case_nodes_have_unhashable_type_raises_type_error():
    # visited is a set, so unhashable nodes should raise TypeError
    graph = {
        ["list_node"]: []  # type: ignore[list-item]  # dict key must be hashable
    }
    with pytest.raises(TypeError):
        topological_sort(graph)


def test_error_case_neighbors_is_not_iterable_raises_type_error():
    graph = {"a": 123}  # graph.get(node, []) is used in: for neighbor in ...
    with pytest.raises(TypeError):
        topological_sort(graph)
